{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a topological embedding task. To maximize empty cells (E), we need to find the smallest possible representation of the color adjacency graph that preserves connectivity and adjacency. This requires graph analysis and a layout strategy.",
  "helpers": [
    {
      "label": "graph_analyzer",
      "instructions": "Analyze the input 50x50 grid to extract two things: 1. The adjacency graph of colors 1 to M (which colors are adjacent to which). 2. The connectivity requirements (ensure each color can be represented by a single connected component). Identify if the adjacency graph is a simple path, a tree, or contains cycles."
    },
    {
      "label": "layout_optimizer",
      "instructions": "Given the adjacency graph of colors 1 to M, propose a compact 50x50 grid layout. The goal is to use the minimum number of cells for each color to satisfy the adjacency requirements. For example, if color A is adjacent to B and C, A must be placed such that it touches at least one cell of B and one cell of C. Suggest a strategy such as a snake-like path for a path graph or a star-like layout for a central hub color."
    },
    {
      "label": "code_generator",
      "instructions": "Write a Python script main.py that reads the 50x50 grid from stdin, extracts the adjacency graph, and implements a robust layout algorithm (like a BFS-based placement or a greedy path-filling algorithm) to output a valid 50x50 grid. The code must ensure that every color is connected and that no two colors are adjacent unless they were adjacent in the input. The code should prioritize minimizing the number of non-zero cells to maximize E."
    }
  ],
  "synthesis_brief": "Combine the adjacency graph data and the layout strategy into a single, robust Python script. The final script must read the input grid, build the adjacency list, use the layout strategy to assign coordinates to colors, and print the resulting 50x50 grid to stdout."
}

